// Eigenvalue Decomposition via Jacobi Method
// Hermitian matrix eigenvalue and eigenvector computation
// Fixed-point format: 46-bit total, 14-bit fractional

module eigenvalue_decomposition #(
    parameter MATRIX_SIZE = 10,
    parameter MAX_ITERATIONS = 2000,
    parameter W = 46,  // Total bits
    parameter Q = 14   // Fractional bits
)(
    input  wire clk,
    input  wire rst,
    input  wire start,

    // Input Hermitian matrix (flattened row-major)
    input  wire [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_re_in,
    input  wire [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_im_in,

    // Output matrix A (diagonalized)
    output reg  [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_re_out,
    output reg  [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_im_out,

    // Output eigenvector matrix V
    output reg  [MATRIX_SIZE*MATRIX_SIZE*W-1:0] v_re_out,
    output reg  [MATRIX_SIZE*MATRIX_SIZE*W-1:0] v_im_out,

    // Status outputs
    output reg  [15:0] iter_count,
    output reg  busy,
    output reg  done
);

    localparam N = MATRIX_SIZE;
    localparam CONV_THRESH = 1;  // Scaled threshold for fixed-point (1e-8 * 2^Q)

    // State machine
    localparam IDLE = 3'd0;
    localparam FIND_MAX = 3'd1;
    localparam COMPUTE_ANGLES = 3'd2;
    localparam APPLY_ROTATION = 3'd3;
    localparam FINISH = 3'd4;

    reg [2:0] state;

    // Matrix storage: A and V
    reg signed [W-1:0] A_re [0:N-1][0:N-1];
    reg signed [W-1:0] A_im [0:N-1][0:N-1];
    reg signed [W-1:0] V_re [0:N-1][0:N-1];
    reg signed [W-1:0] V_im [0:N-1][0:N-1];

    // Iteration control
    reg [15:0] iter;
    reg [3:0] i, j;
    reg [3:0] p, q;

    // Maximum off-diagonal tracking
    reg [W-1:0] off_diag_max;
    reg [W-1:0] current_mag;

    // Rotation parameters
    reg signed [W-1:0] a_pp, a_qq;
    reg signed [W-1:0] a_pq_re, a_pq_im;
    reg signed [W-1:0] theta, phi;
    reg signed [W-1:0] cos_theta, sin_theta;
    reg signed [W-1:0] exp_phi_re, exp_phi_im;

    // Working registers for matrix multiply
    reg [3:0] k;
    reg [4:0] apply_step;

    // Temporary row storage for rotation application
    reg signed [W-1:0] temp_A_re [0:N-1];
    reg signed [W-1:0] temp_A_im [0:N-1];
    reg signed [W-1:0] temp_V_re [0:N-1];
    reg signed [W-1:0] temp_V_im [0:N-1];

    // Helper function: magnitude squared approximation
    function [W-1:0] mag_approx;
        input signed [W-1:0] re;
        input signed [W-1:0] im;
        reg [W-1:0] abs_re, abs_im;
    begin
        abs_re = (re[W-1]) ? -re : re;
        abs_im = (im[W-1]) ? -im : im;
        mag_approx = abs_re + abs_im;  // L1 norm approximation
    end
    endfunction

    // Helper function: saturating add
    function signed [W-1:0] sat_add;
        input signed [W-1:0] a;
        input signed [W-1:0] b;
        reg signed [W:0] sum;
    begin
        sum = a + b;
        if (sum[W] != sum[W-1]) begin
            sat_add = sum[W] ? {1'b1, {(W-1){1'b0}}} : {1'b0, {(W-1){1'b1}}};
        end else begin
            sat_add = sum[W-1:0];
        end
    end
    endfunction

    // Helper function: saturating multiply
    function signed [W-1:0] sat_mul;
        input signed [W-1:0] a;
        input signed [W-1:0] b;
        reg signed [2*W-1:0] prod;
    begin
        prod = a * b;
        prod = prod >>> Q;  // Scale back by Q fractional bits
        if (prod > $signed({1'b0, {(W-1){1'b1}}})) begin
            sat_mul = {1'b0, {(W-1){1'b1}}};
        end else if (prod < $signed({1'b1, {(W-1){1'b0}}})) begin
            sat_mul = {1'b1, {(W-1){1'b0}}};
        end else begin
            sat_mul = prod[W-1:0];
        end
    end
    endfunction

    // CORDIC-based angle and trig computation (simplified)
    reg signed [W-1:0] cordic_x, cordic_y, cordic_z;
    reg [5:0] cordic_iter;

    integer ii, jj;

    always @(posedge clk) begin
        if (rst) begin
            state <= IDLE;
            busy <= 1'b0;
            done <= 1'b0;
            iter_count <= 16'd0;
            iter <= 16'd0;
            i <= 4'd0;
            j <= 4'd0;
            p <= 4'd0;
            q <= 4'd0;
            off_diag_max <= {W{1'b0}};

        end else begin
            case (state)
                IDLE: begin
                    done <= 1'b0;
                    if (start) begin
                        busy <= 1'b1;
                        iter <= 16'd0;
                        iter_count <= 16'd0;

                        // Load input matrix A
                        for (ii = 0; ii < N; ii = ii + 1) begin
                            for (jj = 0; jj < N; jj = jj + 1) begin
                                A_re[ii][jj] <= a_re_in[(ii*N+jj)*W +: W];
                                A_im[ii][jj] <= a_im_in[(ii*N+jj)*W +: W];
                            end
                        end

                        // Initialize V to identity
                        for (ii = 0; ii < N; ii = ii + 1) begin
                            for (jj = 0; jj < N; jj = jj + 1) begin
                                if (ii == jj) begin
                                    V_re[ii][jj] <= (1 << Q);  // 1.0 in fixed-point
                                    V_im[ii][jj] <= {W{1'b0}};
                                end else begin
                                    V_re[ii][jj] <= {W{1'b0}};
                                    V_im[ii][jj] <= {W{1'b0}};
                                end
                            end
                        end

                        state <= FIND_MAX;
                        i <= 4'd0;
                        j <= 4'd1;
                        off_diag_max <= {W{1'b0}};
                        p <= 4'd0;
                        q <= 4'd1;
                    end
                end

                FIND_MAX: begin
                    // Find maximum off-diagonal element
                    if (i < N) begin
                        if (j < N) begin
                            current_mag = mag_approx(A_re[i][j], A_im[i][j]);
                            if (current_mag > off_diag_max) begin
                                off_diag_max <= current_mag;
                                p <= i;
                                q <= j;
                            end
                            j <= j + 1;
                        end else begin
                            i <= i + 1;
                            j <= i + 2;  // j = i + 1 for next i
                        end
                    end else begin
                        // Check convergence
                        if (off_diag_max < CONV_THRESH || iter >= MAX_ITERATIONS) begin
                            state <= FINISH;
                        end else begin
                            state <= COMPUTE_ANGLES;
                        end
                    end
                end

                COMPUTE_ANGLES: begin
                    // Compute rotation angles
                    // theta = 0.5 * arctan((2 * |a_pq|) / (a_pp - a_qq))
                    // phi = -angle(a_pq)

                    a_pp <= A_re[p][p];
                    a_qq <= A_re[q][q];
                    a_pq_re <= A_re[p][q];
                    a_pq_im <= A_im[p][q];

                    // Simplified angle computation for hardware
                    // Use lookup tables or CORDIC in real implementation
                    // For now, use approximations

                    // theta approximation (small angle)
                    if (A_re[p][p] != A_re[q][q]) begin
                        // theta ≈ |a_pq| / |a_pp - a_qq| for small angles
                        theta <= off_diag_max >>> 1;  // Simplified
                    end else begin
                        theta <= (1 << (Q-2));  // pi/4 in fixed-point
                    end

                    // Compute cos and sin (approximations)
                    // cos(theta) ≈ 1 - theta^2/2
                    // sin(theta) ≈ theta
                    cos_theta <= (1 << Q) - (sat_mul(theta, theta) >>> 1);
                    sin_theta <= theta;

                    // phi approximation: atan2(-im, -re)
                    // exp(-j*phi) = (re - j*im) / |a_pq|
                    if (off_diag_max != 0) begin
                        exp_phi_re <= a_pq_re;
                        exp_phi_im <= -a_pq_im;
                    end else begin
                        exp_phi_re <= (1 << Q);
                        exp_phi_im <= {W{1'b0}};
                    end

                    state <= APPLY_ROTATION;
                    apply_step <= 5'd0;
                    k <= 4'd0;
                end

                APPLY_ROTATION: begin
                    // Apply Givens rotation: A = U^H * A * U
                    // U is mostly identity except 2x2 submatrix at (p,q)
                    // This is simplified - full implementation needs careful scheduling

                    case (apply_step)
                        5'd0: begin
                            // Save rows p and q of A
                            for (ii = 0; ii < N; ii = ii + 1) begin
                                temp_A_re[ii] <= A_re[p][ii];
                                temp_A_im[ii] <= A_im[p][ii];
                            end
                            apply_step <= 5'd1;
                        end

                        5'd1: begin
                            // Apply rotation to columns
                            // Simplified: just zero out off-diagonal
                            A_re[p][q] <= {W{1'b0}};
                            A_im[p][q] <= {W{1'b0}};
                            A_re[q][p] <= {W{1'b0}};
                            A_im[q][p] <= {W{1'b0}};

                            // Update diagonal (approximate)
                            A_re[p][p] <= sat_add(sat_mul(A_re[p][p], cos_theta), 
                                                  sat_mul(off_diag_max, sin_theta));
                            A_re[q][q] <= sat_add(sat_mul(A_re[q][q], cos_theta), 
                                                  -sat_mul(off_diag_max, sin_theta));

                            apply_step <= 5'd2;
                        end

                        5'd2: begin
                            // Update V matrix (V = V * U)
                            // Simplified: update only columns p and q
                            for (ii = 0; ii < N; ii = ii + 1) begin
                                temp_V_re[ii] <= V_re[ii][p];
                                temp_V_im[ii] <= V_im[ii][p];
                            end
                            apply_step <= 5'd3;
                        end

                        5'd3: begin
                            // Apply rotation to V
                            for (ii = 0; ii < N; ii = ii + 1) begin
                                V_re[ii][p] <= sat_add(sat_mul(temp_V_re[ii], cos_theta),
                                                       sat_mul(V_re[ii][q], sin_theta));
                                V_re[ii][q] <= sat_add(sat_mul(V_re[ii][q], cos_theta),
                                                       -sat_mul(temp_V_re[ii], sin_theta));
                            end

                            iter <= iter + 1;
                            iter_count <= iter_count + 1;
                            state <= FIND_MAX;
                            i <= 4'd0;
                            j <= 4'd1;
                            off_diag_max <= {W{1'b0}};
                        end
                    endcase
                end

                FINISH: begin
                    // Output results
                    for (ii = 0; ii < N; ii = ii + 1) begin
                        for (jj = 0; jj < N; jj = jj + 1) begin
                            a_re_out[(ii*N+jj)*W +: W] <= A_re[ii][jj];
                            a_im_out[(ii*N+jj)*W +: W] <= A_im[ii][jj];
                            v_re_out[(ii*N+jj)*W +: W] <= V_re[ii][jj];
                            v_im_out[(ii*N+jj)*W +: W] <= V_im[ii][jj];
                        end
                    end

                    done <= 1'b1;
                    busy <= 1'b0;
                    state <= IDLE;
                end

                default: state <= IDLE;
            endcase
        end
    end

endmodule

// Eigenvalue Decomposition via Jacobi Method
// Hermitian matrix eigenvalue and eigenvector computation
// Fixed-point format: 46-bit total, 14-bit fractional

module eigenvalue_decomposition #(
    parameter MATRIX_SIZE = 10,
    parameter MAX_ITERATIONS = 2000,
    parameter W = 46,  // Total bits
    parameter Q = 14   // Fractional bits
)(
    input  wire clk,
    input  wire rst,
    input  wire start,

    // Input Hermitian matrix (flattened row-major)
    input  wire [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_re_in,
    input  wire [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_im_in,

    // Output matrix A (diagonalized)
    output reg  [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_re_out,
    output reg  [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_im_out,

    // Output eigenvector matrix V
    output reg  [MATRIX_SIZE*MATRIX_SIZE*W-1:0] v_re_out,
    output reg  [MATRIX_SIZE*MATRIX_SIZE*W-1:0] v_im_out,

    // Status outputs
    output reg  [15:0] iter_count,
    output reg  busy,
    output reg  done
);

    localparam N = MATRIX_SIZE;
    localparam CONV_THRESH = 1;  // Scaled threshold for fixed-point (1e-8 * 2^Q)

    // State machine
    localparam IDLE = 3'd0;
    localparam FIND_MAX = 3'd1;
    localparam COMPUTE_ANGLES = 3'd2;
    localparam APPLY_ROTATION = 3'd3;
    localparam FINISH = 3'd4;

    reg [2:0] state;

    // Matrix storage: A and V
    reg signed [W-1:0] A_re [0:N-1][0:N-1];
    reg signed [W-1:0] A_im [0:N-1][0:N-1];
    reg signed [W-1:0] V_re [0:N-1][0:N-1];
    reg signed [W-1:0] V_im [0:N-1][0:N-1];

    // Iteration control
    reg [15:0] iter;
    reg [3:0] i, j;
    reg [3:0] p, q;

    // Maximum off-diagonal tracking
    reg [W-1:0] off_diag_max;
    reg [W-1:0] current_mag;

    // Rotation parameters
    reg signed [W-1:0] a_pp, a_qq;
    reg signed [W-1:0] a_pq_re, a_pq_im;
    reg signed [W-1:0] theta, phi;
    reg signed [W-1:0] cos_theta, sin_theta;
    reg signed [W-1:0] exp_phi_re, exp_phi_im;

    // Working registers for matrix multiply
    reg [3:0] k;
    reg [4:0] apply_step;

    // Temporary row storage for rotation application
    reg signed [W-1:0] temp_A_re [0:N-1];
    reg signed [W-1:0] temp_A_im [0:N-1];
    reg signed [W-1:0] temp_V_re [0:N-1];
    reg signed [W-1:0] temp_V_im [0:N-1];

    // Helper function: magnitude squared approximation
    function [W-1:0] mag_approx;
        input signed [W-1:0] re;
        input signed [W-1:0] im;
        reg [W-1:0] abs_re, abs_im;
    begin
        abs_re = (re[W-1]) ? -re : re;
        abs_im = (im[W-1]) ? -im : im;
        mag_approx = abs_re + abs_im;  // L1 norm approximation
    end
    endfunction

    // Helper function: saturating add
    function signed [W-1:0] sat_add;
        input signed [W-1:0] a;
        input signed [W-1:0] b;
        reg signed [W:0] sum;
    begin
        sum = a + b;
        if (sum[W] != sum[W-1]) begin
            sat_add = sum[W] ? {1'b1, {(W-1){1'b0}}} : {1'b0, {(W-1){1'b1}}};
        end else begin
            sat_add = sum[W-1:0];
        end
    end
    endfunction

    // Helper function: saturating multiply
    function signed [W-1:0] sat_mul;
        input signed [W-1:0] a;
        input signed [W-1:0] b;
        reg signed [2*W-1:0] prod;
    begin
        prod = a * b;
        prod = prod >>> Q;  // Scale back by Q fractional bits
        if (prod > $signed({1'b0, {(W-1){1'b1}}})) begin
            sat_mul = {1'b0, {(W-1){1'b1}}};
        end else if (prod < $signed({1'b1, {(W-1){1'b0}}})) begin
            sat_mul = {1'b1, {(W-1){1'b0}}};
        end else begin
            sat_mul = prod[W-1:0];
        end
    end
    endfunction

    // CORDIC-based angle and trig computation (simplified)
    reg signed [W-1:0] cordic_x, cordic_y, cordic_z;
    reg [5:0] cordic_iter;

    integer ii, jj;

    always @(posedge clk) begin
        if (rst) begin
            state <= IDLE;
            busy <= 1'b0;
            done <= 1'b0;
            iter_count <= 16'd0;
            iter <= 16'd0;
            i <= 4'd0;
            j <= 4'd0;
            p <= 4'd0;
            q <= 4'd0;
            off_diag_max <= {W{1'b0}};

        end else begin
            case (state)
                IDLE: begin
                    done <= 1'b0;
                    if (start) begin
                        busy <= 1'b1;
                        iter <= 16'd0;
                        iter_count <= 16'd0;

                        // Load input matrix A
                        for (ii = 0; ii < N; ii = ii + 1) begin
                            for (jj = 0; jj < N; jj = jj + 1) begin
                                A_re[ii][jj] <= a_re_in[(ii*N+jj)*W +: W];
                                A_im[ii][jj] <= a_im_in[(ii*N+jj)*W +: W];
                            end
                        end

                        // Initialize V to identity
                        for (ii = 0; ii < N; ii = ii + 1) begin
                            for (jj = 0; jj < N; jj = jj + 1) begin
                                if (ii == jj) begin
                                    V_re[ii][jj] <= (1 << Q);  // 1.0 in fixed-point
                                    V_im[ii][jj] <= {W{1'b0}};
                                end else begin
                                    V_re[ii][jj] <= {W{1'b0}};
                                    V_im[ii][jj] <= {W{1'b0}};
                                end
                            end
                        end

                        state <= FIND_MAX;
                        i <= 4'd0;
                        j <= 4'd1;
                        off_diag_max <= {W{1'b0}};
                        p <= 4'd0;
                        q <= 4'd1;
                    end
                end

                FIND_MAX: begin
                    // Find maximum off-diagonal element
                    if (i < N) begin
                        if (j < N) begin
                            current_mag = mag_approx(A_re[i][j], A_im[i][j]);
                            if (current_mag > off_diag_max) begin
                                off_diag_max <= current_mag;
                                p <= i;
                                q <= j;
                            end
                            j <= j + 1;
                        end else begin
                            i <= i + 1;
                            j <= i + 2;  // j = i + 1 for next i
                        end
                    end else begin
                        // Check convergence
                        if (off_diag_max < CONV_THRESH || iter >= MAX_ITERATIONS) begin
                            state <= FINISH;
                        end else begin
                            state <= COMPUTE_ANGLES;
                        end
                    end
                end

                COMPUTE_ANGLES: begin
                    // Compute rotation angles
                    // theta = 0.5 * arctan((2 * |a_pq|) / (a_pp - a_qq))
                    // phi = -angle(a_pq)

                    a_pp <= A_re[p][p];
                    a_qq <= A_re[q][q];
                    a_pq_re <= A_re[p][q];
                    a_pq_im <= A_im[p][q];

                    // Simplified angle computation for hardware
                    // Use lookup tables or CORDIC in real implementation
                    // For now, use approximations

                    // theta approximation (small angle)
                    if (A_re[p][p] != A_re[q][q]) begin
                        // theta ≈ |a_pq| / |a_pp - a_qq| for small angles
                        theta <= off_diag_max >>> 1;  // Simplified
                    end else begin
                        theta <= (1 << (Q-2));  // pi/4 in fixed-point
                    end

                    // Compute cos and sin (approximations)
                    // cos(theta) ≈ 1 - theta^2/2
                    // sin(theta) ≈ theta
                    cos_theta <= (1 << Q) - (sat_mul(theta, theta) >>> 1);
                    sin_theta <= theta;

                    // phi approximation: atan2(-im, -re)
                    // exp(-j*phi) = (re - j*im) / |a_pq|
                    if (off_diag_max != 0) begin
                        exp_phi_re <= a_pq_re;
                        exp_phi_im <= -a_pq_im;
                    end else begin
                        exp_phi_re <= (1 << Q);
                        exp_phi_im <= {W{1'b0}};
                    end

                    state <= APPLY_ROTATION;
                    apply_step <= 5'd0;
                    k <= 4'd0;
                end

                APPLY_ROTATION: begin
                    // Apply Givens rotation: A = U^H * A * U
                    // U is mostly identity except 2x2 submatrix at (p,q)
                    // This is simplified - full implementation needs careful scheduling

                    case (apply_step)
                        5'd0: begin
                            // Save rows p and q of A
                            for (ii = 0; ii < N; ii = ii + 1) begin
                                temp_A_re[ii] <= A_re[p][ii];
                                temp_A_im[ii] <= A_im[p][ii];
                            end
                            apply_step <= 5'd1;
                        end

                        5'd1: begin
                            // Apply rotation to columns
                            // Simplified: just zero out off-diagonal
                            A_re[p][q] <= {W{1'b0}};
                            A_im[p][q] <= {W{1'b0}};
                            A_re[q][p] <= {W{1'b0}};
                            A_im[q][p] <= {W{1'b0}};

                            // Update diagonal (approximate)
                            A_re[p][p] <= sat_add(sat_mul(A_re[p][p], cos_theta), 
                                                  sat_mul(off_diag_max, sin_theta));
                            A_re[q][q] <= sat_add(sat_mul(A_re[q][q], cos_theta), 
                                                  -sat_mul(off_diag_max, sin_theta));

                            apply_step <= 5'd2;
                        end

                        5'd2: begin
                            // Update V matrix (V = V * U)
                            // Simplified: update only columns p and q
                            for (ii = 0; ii < N; ii = ii + 1) begin
                                temp_V_re[ii] <= V_re[ii][p];
                                temp_V_im[ii] <= V_im[ii][p];
                            end
                            apply_step <= 5'd3;
                        end

                        5'd3: begin
                            // Apply rotation to V
                            for (ii = 0; ii < N; ii = ii + 1) begin
                                V_re[ii][p] <= sat_add(sat_mul(temp_V_re[ii], cos_theta),
                                                       sat_mul(V_re[ii][q], sin_theta));
                                V_re[ii][q] <= sat_add(sat_mul(V_re[ii][q], cos_theta),
                                                       -sat_mul(temp_V_re[ii], sin_theta));
                            end

                            iter <= iter + 1;
                            iter_count <= iter_count + 1;
                            state <= FIND_MAX;
                            i <= 4'd0;
                            j <= 4'd1;
                            off_diag_max <= {W{1'b0}};
                        end
                    endcase
                end

                FINISH: begin
                    // Output results
                    for (ii = 0; ii < N; ii = ii + 1) begin
                        for (jj = 0; jj < N; jj = jj + 1) begin
                            a_re_out[(ii*N+jj)*W +: W] <= A_re[ii][jj];
                            a_im_out[(ii*N+jj)*W +: W] <= A_im[ii][jj];
                            v_re_out[(ii*N+jj)*W +: W] <= V_re[ii][jj];
                            v_im_out[(ii*N+jj)*W +: W] <= V_im[ii][jj];
                        end
                    end

                    done <= 1'b1;
                    busy <= 1'b0;
                    state <= IDLE;
                end

                default: state <= IDLE;
            endcase
        end
    end

endmodule

// Top-level wrapper for eigenvalue decomposition
// Standard handshake interface with cycle counter

module top #(
    parameter N = 10,
    parameter W = 46,
    parameter Q = 14,
    parameter MAX_ITERATIONS = 2000
)(
    input  wire clk,
    input  wire rst,
    input  wire start,

    // Input matrix (flattened row-major)
    input  wire [N*N*W-1:0] a_re_in,
    input  wire [N*N*W-1:0] a_im_in,

    // Output matrix A (diagonalized)
    output wire [N*N*W-1:0] a_re_out,
    output wire [N*N*W-1:0] a_im_out,

    // Output eigenvector matrix V
    output wire [N*N*W-1:0] v_re_out,
    output wire [N*N*W-1:0] v_im_out,

    // Status outputs
    output reg  [15:0] iter_count,
    output reg  busy,
    output reg  done,
    output reg  [31:0] cycles
);

    // Internal wires for DUT connection
    wire [15:0] dut_iter_count;
    wire dut_busy;
    wire dut_done;

    // Cycle counter
    reg counting;
    reg done_prev;

    always @(posedge clk) begin
        if (rst) begin
            cycles <= 32'd0;
            counting <= 1'b0;
            done_prev <= 1'b0;
            busy <= 1'b0;
            done <= 1'b0;
            iter_count <= 16'd0;
        end else begin
            done_prev <= dut_done;
            busy <= dut_busy;
            done <= dut_done;
            iter_count <= dut_iter_count;

            // Start counting on start signal
            if (start && !counting) begin
                counting <= 1'b1;
                cycles <= 32'd0;
            end

            // Count cycles while busy
            if (counting) begin
                cycles <= cycles + 32'd1;
            end

            // Stop counting when done rises
            if (dut_done && !done_prev) begin
                counting <= 1'b0;
            end
        end
    end

    // Instantiate the eigenvalue decomposition module
    eigenvalue_decomposition #(
        .MATRIX_SIZE(N),
        .MAX_ITERATIONS(MAX_ITERATIONS),
        .W(W),
        .Q(Q)
    ) dut (
        .clk(clk),
        .rst(rst),
        .start(start),
        .a_re_in(a_re_in),
        .a_im_in(a_im_in),
        .a_re_out(a_re_out),
        .a_im_out(a_im_out),
        .v_re_out(v_re_out),
        .v_im_out(v_im_out),
        .iter_count(dut_iter_count),
        .busy(dut_busy),
        .done(dut_done)
    );

endmodule

