`timescale 1ns/1ps

module tb_top();

    // Parameters
    parameter N = 10;
    parameter W = 46;
    parameter Q = 14;
    parameter MAX_ITERATIONS = 2000;
    parameter CLK_PERIOD = 10;  // 100 MHz

    // DUT signals
    reg clk;
    reg rst;
    reg start;
    reg [N*N*W-1:0] a_re_in;
    reg [N*N*W-1:0] a_im_in;
    wire [N*N*W-1:0] a_re_out;
    wire [N*N*W-1:0] a_im_out;
    wire [N*N*W-1:0] v_re_out;
    wire [N*N*W-1:0] v_im_out;
    wire [15:0] iter_count;
    wire busy;
    wire done;
    wire [31:0] cycles;

    // Memory for input data
    reg signed [W-1:0] input_re [0:N*N-1];
    reg signed [W-1:0] input_im [0:N*N-1];

    // Memory for output data
    reg signed [W-1:0] output_re [0:N*N-1];
    reg signed [W-1:0] output_im [0:N*N-1];

    integer i, j;
    integer input_file, output_file, meta_file;
    integer scan_result;
    reg signed [W-1:0] re_val, im_val;

    // Clock generation
    initial begin
        clk = 0;
        forever #(CLK_PERIOD/2) clk = ~clk;
    end

    // DUT instantiation
    top #(
        .N(N),
        .W(W),
        .Q(Q),
        .MAX_ITERATIONS(MAX_ITERATIONS)
    ) dut (
        .clk(clk),
        .rst(rst),
        .start(start),
        .a_re_in(a_re_in),
        .a_im_in(a_im_in),
        .a_re_out(a_re_out),
        .a_im_out(a_im_out),
        .v_re_out(v_re_out),
        .v_im_out(v_im_out),
        .iter_count(iter_count),
        .busy(busy),
        .done(done),
        .cycles(cycles)
    );

    // Test procedure
    initial begin
        // Initialize
        rst = 1;
        start = 0;
        a_re_in = {(N*N*W){1'b0}};
        a_im_in = {(N*N*W){1'b0}};

        // Read input file
        input_file = $fopen("../reference_inputs.txt", "r");
        if (input_file == 0) begin
            $display("ERROR: Could not open reference_inputs.txt");
            $finish;
        end

        $display("Reading input matrix from reference_inputs.txt");
        for (i = 0; i < N*N; i = i + 1) begin
            scan_result = $fscanf(input_file, "%d %d\n", re_val, im_val);
            if (scan_result != 2) begin
                $display("ERROR: Failed to read input element %0d", i);
                $finish;
            end
            input_re[i] = re_val;
            input_im[i] = im_val;
        end
        $fclose(input_file);
        $display("Input matrix loaded successfully");

        // Pack input matrix into flat vectors
        for (i = 0; i < N*N; i = i + 1) begin
            a_re_in[i*W +: W] = input_re[i];
            a_im_in[i*W +: W] = input_im[i];
        end

        // Reset
        #(CLK_PERIOD * 5);
        rst = 0;
        #(CLK_PERIOD * 2);

        // Start computation
        $display("Starting eigenvalue decomposition at time %0t", $time);
        start = 1;
        #CLK_PERIOD;
        start = 0;

        // Wait for completion (with timeout)
        fork
            begin
                wait(done);
                $display("Computation completed at time %0t", $time);
                $display("Iterations: %0d, Cycles: %0d", iter_count, cycles);
            end
            begin
                #(CLK_PERIOD * 1000000);  // Timeout after 1M cycles
                $display("ERROR: Timeout waiting for done signal");
                $finish;
            end
        join_any
        disable fork;

        // Wait a few more cycles to ensure outputs are stable
        #(CLK_PERIOD * 5);

        // Unpack output matrix
        for (i = 0; i < N*N; i = i + 1) begin
            output_re[i] = a_re_out[i*W +: W];
            output_im[i] = a_im_out[i*W +: W];
        end

        // Write diagonal elements to output file
        output_file = $fopen("sim/sim_diag_out.txt", "w");
        if (output_file == 0) begin
            $display("ERROR: Could not open sim_diag_out.txt for writing");
            $finish;
        end

        $display("Writing diagonal elements to sim_diag_out.txt");
        for (i = 0; i < N; i = i + 1) begin
            // Diagonal elements are at positions [i*N + i]
            $fwrite(output_file, "%0d %0d\n", output_re[i*N + i], output_im[i*N + i]);
        end
        $fclose(output_file);
        $display("Diagonal elements written successfully");

        // Write metadata
        meta_file = $fopen("sim/sim_meta.txt", "w");
        if (meta_file == 0) begin
            $display("ERROR: Could not open sim_meta.txt for writing");
            $finish;
        end

        $fwrite(meta_file, "iter_count %0d\n", iter_count);
        $fwrite(meta_file, "cycles %0d\n", cycles);
        $fclose(meta_file);
        $display("Metadata written successfully");

        // Finish simulation
        $display("Simulation completed successfully");
        $finish;
    end

    // Watchdog timer
    initial begin
        #(CLK_PERIOD * 2000000);  // 2M cycles max
        $display("ERROR: Simulation watchdog timeout");
        $finish;
    end

endmodule

