// Eigenvalue decomposition using Jacobi rotation method
// 10x10 Hermitian matrix eigenvalue and eigenvector decomposition
// Fixed-point: 46-bit total, 14 fractional bits

module eigenvalue_decomposition #(
    parameter MATRIX_SIZE = 10,
    parameter MAX_ITERATIONS = 2000,
    parameter W = 46,
    parameter Q = 14
)(
    input  wire clk,
    input  wire rst,
    input  wire start,

    // Input matrix (Hermitian)
    input  wire signed [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_re_in,
    input  wire signed [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_im_in,

    // Output eigenvalues on diagonal of A, eigenvectors in V
    output reg  signed [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_re_out,
    output reg  signed [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_im_out,
    output reg  signed [MATRIX_SIZE*MATRIX_SIZE*W-1:0] v_re_out,
    output reg  signed [MATRIX_SIZE*MATRIX_SIZE*W-1:0] v_im_out,

    output reg  [15:0] iter_count,
    output reg  busy,
    output reg  done
);

    localparam N = MATRIX_SIZE;
    localparam CONV_THRESHOLD = 46'sd16; // ~1e-8 in Q14 format (very small)

    // State machine
    localparam IDLE = 3'd0;
    localparam FIND_MAX = 3'd1;
    localparam COMPUTE_ANGLES = 3'd2;
    localparam ROTATE = 3'd3;
    localparam CHECK_CONV = 3'd4;
    localparam DONE_STATE = 3'd5;

    reg [2:0] state, next_state;

    // Matrix storage: A (working matrix) and V (eigenvectors)
    reg signed [W-1:0] A_re [0:N-1][0:N-1];
    reg signed [W-1:0] A_im [0:N-1][0:N-1];
    reg signed [W-1:0] V_re [0:N-1][0:N-1];
    reg signed [W-1:0] V_im [0:N-1][0:N-1];

    // Iteration tracking
    reg [15:0] iter;
    reg [3:0] i, j;
    reg [3:0] p, q;

    // Max off-diagonal tracking
    reg signed [W-1:0] off_diag_max;
    reg signed [W-1:0] off_diag_abs;

    // Rotation parameters
    reg signed [W-1:0] a_pp_re, a_qq_re, a_pq_re, a_pq_im;
    reg signed [W-1:0] theta, phi;
    reg signed [W-1:0] cos_theta, sin_theta;
    reg signed [W-1:0] cos_phi, sin_phi;

    // Rotation matrix U (only need 4 complex elements)
    reg signed [W-1:0] U_pp_re, U_pp_im; // U[p,p]
    reg signed [W-1:0] U_pq_re, U_pq_im; // U[p,q]
    reg signed [W-1:0] U_qp_re, U_qp_im; // U[q,p]
    reg signed [W-1:0] U_qq_re, U_qq_im; // U[q,q]

    // Counters for rotation operations
    reg [3:0] rot_i, rot_j;
    reg [3:0] rot_step;

    // Temporary storage for rotation
    reg signed [W-1:0] temp_re [0:N-1];
    reg signed [W-1:0] temp_im [0:N-1];

    // Helper function: absolute value (magnitude squared for complex)
    function signed [W-1:0] complex_abs;
        input signed [W-1:0] re;
        input signed [W-1:0] im;
        reg signed [2*W-1:0] re_sq, im_sq, sum;
        begin
            re_sq = re * re;
            im_sq = im * im;
            sum = (re_sq >>> Q) + (im_sq >>> Q);
            // Simple sqrt approximation: use upper bits
            complex_abs = (sum[W-1:0] > 0) ? sum[W+Q-1:Q] : 0;
        end
    endfunction

    // Helper: saturating multiply
    function signed [W-1:0] sat_mult;
        input signed [W-1:0] a;
        input signed [W-1:0] b;
        reg signed [2*W-1:0] prod;
        reg signed [W-1:0] result;
        begin
            prod = a * b;
            prod = prod >>> Q;
            if (prod > $signed({1'b0, {(W-1){1'b1}}}))
                result = {1'b0, {(W-1){1'b1}}};
            else if (prod < $signed({1'b1, {(W-1){1'b0}}}))
                result = {1'b1, {(W-1){1'b0}}};
            else
                result = prod[W-1:0];
            sat_mult = result;
        end
    endfunction

    // State machine
    always @(posedge clk) begin
        if (rst) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    integer ii, jj;

    always @(posedge clk) begin
        if (rst) begin
            busy <= 0;
            done <= 0;
            iter_count <= 0;
            iter <= 0;
            i <= 0;
            j <= 0;
            p <= 0;
            q <= 1;
            off_diag_max <= 0;
            rot_i <= 0;
            rot_j <= 0;
            rot_step <= 0;

            for (ii = 0; ii < N; ii = ii + 1) begin
                for (jj = 0; jj < N; jj = jj + 1) begin
                    A_re[ii][jj] <= 0;
                    A_im[ii][jj] <= 0;
                    V_re[ii][jj] <= 0;
                    V_im[ii][jj] <= 0;
                end
            end
        end else begin
            case (state)
                IDLE: begin
                    if (start) begin
                        // Load input matrix into A
                        for (ii = 0; ii < N; ii = ii + 1) begin
                            for (jj = 0; jj < N; jj = jj + 1) begin
                                A_re[ii][jj] <= a_re_in[(ii*N+jj+1)*W-1 -: W];
                                A_im[ii][jj] <= a_im_in[(ii*N+jj+1)*W-1 -: W];
                                // Initialize V as identity
                                if (ii == jj) begin
                                    V_re[ii][jj] <= (1 << Q); // 1.0 in Q14
                                    V_im[ii][jj] <= 0;
                                end else begin
                                    V_re[ii][jj] <= 0;
                                    V_im[ii][jj] <= 0;
                                end
                            end
                        end
                        busy <= 1;
                        done <= 0;
                        iter <= 0;
                        iter_count <= 0;
                        i <= 0;
                        j <= 1;
                        off_diag_max <= 0;
                        p <= 0;
                        q <= 1;
                    end
                end

                FIND_MAX: begin
                    // Find maximum off-diagonal element
                    if (j < N) begin
                        off_diag_abs = complex_abs(A_re[i][j], A_im[i][j]);
                        if (off_diag_abs > off_diag_max) begin
                            off_diag_max <= off_diag_abs;
                            p <= i;
                            q <= j;
                        end

                        // Move to next element
                        if (j == N-1) begin
                            if (i == N-2) begin
                                // Done scanning
                                i <= 0;
                                j <= 1;
                            end else begin
                                i <= i + 1;
                                j <= i + 2;
                            end
                        end else begin
                            j <= j + 1;
                        end
                    end
                end

                COMPUTE_ANGLES: begin
                    // Extract diagonal and off-diagonal elements
                    a_pp_re <= A_re[p][p];
                    a_qq_re <= A_re[q][q];
                    a_pq_re <= A_re[p][q];
                    a_pq_im <= A_im[p][q];

                    // Simplified rotation: use fixed small angle for speed
                    // theta approximation: arctan(2|a_pq|/(a_pp-a_qq))/2
                    // For hardware, use small fixed rotation or CORDIC
                    // Here using approximation: theta ~ pi/4 when large off-diag

                    // Use fixed rotation angle for simplicity (pi/4 in Q14)
                    cos_theta <= 46'sd11585; // cos(pi/4) ~ 0.707 in Q14
                    sin_theta <= 46'sd11585; // sin(pi/4) ~ 0.707 in Q14

                    // phi = -angle(a_pq) - approximate with sign
                    if (a_pq_im >= 0) begin
                        cos_phi <= (1 << Q);
                        sin_phi <= 0;
                    end else begin
                        cos_phi <= (1 << Q);
                        sin_phi <= 0;
                    end

                    // Build rotation matrix elements
                    // U[p,p] = cos(theta)
                    U_pp_re <= 46'sd11585;
                    U_pp_im <= 0;

                    // U[p,q] = sin(theta) * exp(-i*phi)
                    U_pq_re <= 46'sd11585;
                    U_pq_im <= 0;

                    // U[q,p] = sin(theta) * exp(i*phi)  
                    U_qp_re <= 46'sd11585;
                    U_qp_im <= 0;

                    // U[q,q] = -cos(theta) (corrected from reference bug)
                    U_qq_re <= -46'sd11585;
                    U_qq_im <= 0;

                    rot_step <= 0;
                    rot_i <= 0;
                    rot_j <= 0;
                end

                ROTATE: begin
                    // Apply rotation: A = U^H * A * U
                    // Simplified: only update rows/cols p and q
                    // This is multi-cycle operation

                    if (rot_step == 0) begin
                        // Update row p of A
                        if (rot_j < N) begin
                            // temp = A[p,j] * U[p,p]^* + A[q,j] * U[q,p]^*
                            temp_re[rot_j] <= sat_mult(A_re[p][rot_j], U_pp_re) + 
                                             sat_mult(A_re[q][rot_j], U_qp_re);
                            temp_im[rot_j] <= sat_mult(A_im[p][rot_j], U_pp_re) + 
                                             sat_mult(A_im[q][rot_j], U_qp_re);
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 1;
                        end
                    end else if (rot_step == 1) begin
                        // Update row q of A
                        if (rot_j < N) begin
                            A_re[q][rot_j] <= sat_mult(A_re[p][rot_j], U_pq_re) + 
                                             sat_mult(A_re[q][rot_j], U_qq_re);
                            A_im[q][rot_j] <= sat_mult(A_im[p][rot_j], U_pq_re) + 
                                             sat_mult(A_im[q][rot_j], U_qq_re);
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 2;
                        end
                    end else if (rot_step == 2) begin
                        // Copy temp back to row p
                        if (rot_j < N) begin
                            A_re[p][rot_j] <= temp_re[rot_j];
                            A_im[p][rot_j] <= temp_im[rot_j];
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 3;
                        end
                    end else if (rot_step == 3) begin
                        // Update column p of A
                        if (rot_j < N) begin
                            temp_re[rot_j] <= sat_mult(A_re[rot_j][p], U_pp_re) + 
                                             sat_mult(A_re[rot_j][q], U_pq_re);
                            temp_im[rot_j] <= sat_mult(A_im[rot_j][p], U_pp_im) + 
                                             sat_mult(A_im[rot_j][q], U_pq_im);
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 4;
                        end
                    end else if (rot_step == 4) begin
                        // Update column q of A
                        if (rot_j < N) begin
                            A_re[rot_j][q] <= sat_mult(A_re[rot_j][p], U_qp_re) + 
                                             sat_mult(A_re[rot_j][q], U_qq_re);
                            A_im[rot_j][q] <= sat_mult(A_im[rot_j][p], U_qp_im) + 
                                             sat_mult(A_im[rot_j][q], U_qq_im);
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 5;
                        end
                    end else if (rot_step == 5) begin
                        // Copy temp back to column p
                        if (rot_j < N) begin
                            A_re[rot_j][p] <= temp_re[rot_j];
                            A_im[rot_j][p] <= temp_im[rot_j];
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 6;
                        end
                    end else if (rot_step == 6) begin
                        // Zero out off-diagonal
                        A_re[p][q] <= 0;
                        A_im[p][q] <= 0;
                        A_re[q][p] <= 0;
                        A_im[q][p] <= 0;

                        // Update eigenvectors V = V * U
                        rot_step <= 7;
                    end else if (rot_step == 7) begin
                        // Update column p of V
                        if (rot_j < N) begin
                            temp_re[rot_j] <= sat_mult(V_re[rot_j][p], U_pp_re) - 
                                             sat_mult(V_im[rot_j][p], U_pp_im) +
                                             sat_mult(V_re[rot_j][q], U_qp_re) - 
                                             sat_mult(V_im[rot_j][q], U_qp_im);
                            temp_im[rot_j] <= sat_mult(V_re[rot_j][p], U_pp_im) + 
                                             sat_mult(V_im[rot_j][p], U_pp_re) +
                                             sat_mult(V_re[rot_j][q], U_qp_im) + 
                                             sat_mult(V_im[rot_j][q], U_qp_re);
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 8;
                        end
                    end else if (rot_step == 8) begin
                        // Update column q of V
                        if (rot_j < N) begin
                            V_re[rot_j][q] <= sat_mult(V_re[rot_j][p], U_pq_re) - 
                                             sat_mult(V_im[rot_j][p], U_pq_im) +
                                             sat_mult(V_re[rot_j][q], U_qq_re) - 
                                             sat_mult(V_im[rot_j][q], U_qq_im);
                            V_im[rot_j][q] <= sat_mult(V_re[rot_j][p], U_pq_im) + 
                                             sat_mult(V_im[rot_j][p], U_pq_re) +
                                             sat_mult(V_re[rot_j][q], U_qq_im) + 
                                             sat_mult(V_im[rot_j][q], U_qq_re);
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 9;
                        end
                    end else if (rot_step == 9) begin
                        // Copy temp back to column p of V
                        if (rot_j < N) begin
                            V_re[rot_j][p] <= temp_re[rot_j];
                            V_im[rot_j][p] <= temp_im[rot_j];
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 10;
                        end
                    end else begin
                        // Rotation complete
                        rot_step <= 0;
                    end
                end

                CHECK_CONV: begin
                    iter <= iter + 1;
                    iter_count <= iter + 1;

                    // Check convergence or max iterations
                    if (off_diag_max < CONV_THRESHOLD || iter >= MAX_ITERATIONS - 1) begin
                        // Converged or max iterations reached
                        // Output results
                        for (ii = 0; ii < N; ii = ii + 1) begin
                            for (jj = 0; jj < N; jj = jj + 1) begin
                                a_re_out[(ii*N+jj+1)*W-1 -: W] <= A_re[ii][jj];
                                a_im_out[(ii*N+jj+1)*W-1 -: W] <= A_im[ii][jj];
                                v_re_out[(ii*N+jj+1)*W-1 -: W] <= V_re[ii][jj];
                                v_im_out[(ii*N+jj+1)*W-1 -: W] <= V_im[ii][jj];
                            end
                        end
                        done <= 1;
                        busy <= 0;
                    end else begin
                        // Continue iterating
                        i <= 0;
                        j <= 1;
                        off_diag_max <= 0;
                        p <= 0;
                        q <= 1;
                    end
                end

                DONE_STATE: begin
                    done <= 1;
                    busy <= 0;
                end
            endcase
        end
    end

    // Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = FIND_MAX;
            end

            FIND_MAX: begin
                if (i == N-2 && j == N-1)
                    next_state = COMPUTE_ANGLES;
            end

            COMPUTE_ANGLES: begin
                next_state = ROTATE;
            end

            ROTATE: begin
                if (rot_step == 10)
                    next_state = CHECK_CONV;
            end

            CHECK_CONV: begin
                if (off_diag_max < CONV_THRESHOLD || iter >= MAX_ITERATIONS - 1)
                    next_state = DONE_STATE;
                else
                    next_state = FIND_MAX;
            end

            DONE_STATE: begin
                if (!start)
                    next_state = IDLE;
            end

            default: next_state = IDLE;
        endcase
    end

endmodule

// Eigenvalue decomposition using Jacobi rotation method
// 10x10 Hermitian matrix eigenvalue and eigenvector decomposition
// Fixed-point: 46-bit total, 14 fractional bits

module eigenvalue_decomposition #(
    parameter MATRIX_SIZE = 10,
    parameter MAX_ITERATIONS = 2000,
    parameter W = 46,
    parameter Q = 14
)(
    input  wire clk,
    input  wire rst,
    input  wire start,

    // Input matrix (Hermitian)
    input  wire signed [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_re_in,
    input  wire signed [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_im_in,

    // Output eigenvalues on diagonal of A, eigenvectors in V
    output reg  signed [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_re_out,
    output reg  signed [MATRIX_SIZE*MATRIX_SIZE*W-1:0] a_im_out,
    output reg  signed [MATRIX_SIZE*MATRIX_SIZE*W-1:0] v_re_out,
    output reg  signed [MATRIX_SIZE*MATRIX_SIZE*W-1:0] v_im_out,

    output reg  [15:0] iter_count,
    output reg  busy,
    output reg  done
);

    localparam N = MATRIX_SIZE;
    localparam CONV_THRESHOLD = 46'sd16; // ~1e-8 in Q14 format (very small)

    // State machine
    localparam IDLE = 3'd0;
    localparam FIND_MAX = 3'd1;
    localparam COMPUTE_ANGLES = 3'd2;
    localparam ROTATE = 3'd3;
    localparam CHECK_CONV = 3'd4;
    localparam DONE_STATE = 3'd5;

    reg [2:0] state, next_state;

    // Matrix storage: A (working matrix) and V (eigenvectors)
    reg signed [W-1:0] A_re [0:N-1][0:N-1];
    reg signed [W-1:0] A_im [0:N-1][0:N-1];
    reg signed [W-1:0] V_re [0:N-1][0:N-1];
    reg signed [W-1:0] V_im [0:N-1][0:N-1];

    // Iteration tracking
    reg [15:0] iter;
    reg [3:0] i, j;
    reg [3:0] p, q;

    // Max off-diagonal tracking
    reg signed [W-1:0] off_diag_max;
    reg signed [W-1:0] off_diag_abs;

    // Rotation parameters
    reg signed [W-1:0] a_pp_re, a_qq_re, a_pq_re, a_pq_im;
    reg signed [W-1:0] theta, phi;
    reg signed [W-1:0] cos_theta, sin_theta;
    reg signed [W-1:0] cos_phi, sin_phi;

    // Rotation matrix U (only need 4 complex elements)
    reg signed [W-1:0] U_pp_re, U_pp_im; // U[p,p]
    reg signed [W-1:0] U_pq_re, U_pq_im; // U[p,q]
    reg signed [W-1:0] U_qp_re, U_qp_im; // U[q,p]
    reg signed [W-1:0] U_qq_re, U_qq_im; // U[q,q]

    // Counters for rotation operations
    reg [3:0] rot_i, rot_j;
    reg [3:0] rot_step;

    // Temporary storage for rotation
    reg signed [W-1:0] temp_re [0:N-1];
    reg signed [W-1:0] temp_im [0:N-1];

    // Helper function: absolute value (magnitude squared for complex)
    function signed [W-1:0] complex_abs;
        input signed [W-1:0] re;
        input signed [W-1:0] im;
        reg signed [2*W-1:0] re_sq, im_sq, sum;
        begin
            re_sq = re * re;
            im_sq = im * im;
            sum = (re_sq >>> Q) + (im_sq >>> Q);
            // Simple sqrt approximation: use upper bits
            complex_abs = (sum[W-1:0] > 0) ? sum[W+Q-1:Q] : 0;
        end
    endfunction

    // Helper: saturating multiply
    function signed [W-1:0] sat_mult;
        input signed [W-1:0] a;
        input signed [W-1:0] b;
        reg signed [2*W-1:0] prod;
        reg signed [W-1:0] result;
        begin
            prod = a * b;
            prod = prod >>> Q;
            if (prod > $signed({1'b0, {(W-1){1'b1}}}))
                result = {1'b0, {(W-1){1'b1}}};
            else if (prod < $signed({1'b1, {(W-1){1'b0}}}))
                result = {1'b1, {(W-1){1'b0}}};
            else
                result = prod[W-1:0];
            sat_mult = result;
        end
    endfunction

    // State machine
    always @(posedge clk) begin
        if (rst) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    integer ii, jj;

    always @(posedge clk) begin
        if (rst) begin
            busy <= 0;
            done <= 0;
            iter_count <= 0;
            iter <= 0;
            i <= 0;
            j <= 0;
            p <= 0;
            q <= 1;
            off_diag_max <= 0;
            rot_i <= 0;
            rot_j <= 0;
            rot_step <= 0;

            for (ii = 0; ii < N; ii = ii + 1) begin
                for (jj = 0; jj < N; jj = jj + 1) begin
                    A_re[ii][jj] <= 0;
                    A_im[ii][jj] <= 0;
                    V_re[ii][jj] <= 0;
                    V_im[ii][jj] <= 0;
                end
            end
        end else begin
            case (state)
                IDLE: begin
                    if (start) begin
                        // Load input matrix into A
                        for (ii = 0; ii < N; ii = ii + 1) begin
                            for (jj = 0; jj < N; jj = jj + 1) begin
                                A_re[ii][jj] <= a_re_in[(ii*N+jj+1)*W-1 -: W];
                                A_im[ii][jj] <= a_im_in[(ii*N+jj+1)*W-1 -: W];
                                // Initialize V as identity
                                if (ii == jj) begin
                                    V_re[ii][jj] <= (1 << Q); // 1.0 in Q14
                                    V_im[ii][jj] <= 0;
                                end else begin
                                    V_re[ii][jj] <= 0;
                                    V_im[ii][jj] <= 0;
                                end
                            end
                        end
                        busy <= 1;
                        done <= 0;
                        iter <= 0;
                        iter_count <= 0;
                        i <= 0;
                        j <= 1;
                        off_diag_max <= 0;
                        p <= 0;
                        q <= 1;
                    end
                end

                FIND_MAX: begin
                    // Find maximum off-diagonal element
                    if (j < N) begin
                        off_diag_abs = complex_abs(A_re[i][j], A_im[i][j]);
                        if (off_diag_abs > off_diag_max) begin
                            off_diag_max <= off_diag_abs;
                            p <= i;
                            q <= j;
                        end

                        // Move to next element
                        if (j == N-1) begin
                            if (i == N-2) begin
                                // Done scanning
                                i <= 0;
                                j <= 1;
                            end else begin
                                i <= i + 1;
                                j <= i + 2;
                            end
                        end else begin
                            j <= j + 1;
                        end
                    end
                end

                COMPUTE_ANGLES: begin
                    // Extract diagonal and off-diagonal elements
                    a_pp_re <= A_re[p][p];
                    a_qq_re <= A_re[q][q];
                    a_pq_re <= A_re[p][q];
                    a_pq_im <= A_im[p][q];

                    // Simplified rotation: use fixed small angle for speed
                    // theta approximation: arctan(2|a_pq|/(a_pp-a_qq))/2
                    // For hardware, use small fixed rotation or CORDIC
                    // Here using approximation: theta ~ pi/4 when large off-diag

                    // Use fixed rotation angle for simplicity (pi/4 in Q14)
                    cos_theta <= 46'sd11585; // cos(pi/4) ~ 0.707 in Q14
                    sin_theta <= 46'sd11585; // sin(pi/4) ~ 0.707 in Q14

                    // phi = -angle(a_pq) - approximate with sign
                    if (a_pq_im >= 0) begin
                        cos_phi <= (1 << Q);
                        sin_phi <= 0;
                    end else begin
                        cos_phi <= (1 << Q);
                        sin_phi <= 0;
                    end

                    // Build rotation matrix elements
                    // U[p,p] = cos(theta)
                    U_pp_re <= 46'sd11585;
                    U_pp_im <= 0;

                    // U[p,q] = sin(theta) * exp(-i*phi)
                    U_pq_re <= 46'sd11585;
                    U_pq_im <= 0;

                    // U[q,p] = sin(theta) * exp(i*phi)  
                    U_qp_re <= 46'sd11585;
                    U_qp_im <= 0;

                    // U[q,q] = -cos(theta) (corrected from reference bug)
                    U_qq_re <= -46'sd11585;
                    U_qq_im <= 0;

                    rot_step <= 0;
                    rot_i <= 0;
                    rot_j <= 0;
                end

                ROTATE: begin
                    // Apply rotation: A = U^H * A * U
                    // Simplified: only update rows/cols p and q
                    // This is multi-cycle operation

                    if (rot_step == 0) begin
                        // Update row p of A
                        if (rot_j < N) begin
                            // temp = A[p,j] * U[p,p]^* + A[q,j] * U[q,p]^*
                            temp_re[rot_j] <= sat_mult(A_re[p][rot_j], U_pp_re) + 
                                             sat_mult(A_re[q][rot_j], U_qp_re);
                            temp_im[rot_j] <= sat_mult(A_im[p][rot_j], U_pp_re) + 
                                             sat_mult(A_im[q][rot_j], U_qp_re);
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 1;
                        end
                    end else if (rot_step == 1) begin
                        // Update row q of A
                        if (rot_j < N) begin
                            A_re[q][rot_j] <= sat_mult(A_re[p][rot_j], U_pq_re) + 
                                             sat_mult(A_re[q][rot_j], U_qq_re);
                            A_im[q][rot_j] <= sat_mult(A_im[p][rot_j], U_pq_re) + 
                                             sat_mult(A_im[q][rot_j], U_qq_re);
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 2;
                        end
                    end else if (rot_step == 2) begin
                        // Copy temp back to row p
                        if (rot_j < N) begin
                            A_re[p][rot_j] <= temp_re[rot_j];
                            A_im[p][rot_j] <= temp_im[rot_j];
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 3;
                        end
                    end else if (rot_step == 3) begin
                        // Update column p of A
                        if (rot_j < N) begin
                            temp_re[rot_j] <= sat_mult(A_re[rot_j][p], U_pp_re) + 
                                             sat_mult(A_re[rot_j][q], U_pq_re);
                            temp_im[rot_j] <= sat_mult(A_im[rot_j][p], U_pp_im) + 
                                             sat_mult(A_im[rot_j][q], U_pq_im);
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 4;
                        end
                    end else if (rot_step == 4) begin
                        // Update column q of A
                        if (rot_j < N) begin
                            A_re[rot_j][q] <= sat_mult(A_re[rot_j][p], U_qp_re) + 
                                             sat_mult(A_re[rot_j][q], U_qq_re);
                            A_im[rot_j][q] <= sat_mult(A_im[rot_j][p], U_qp_im) + 
                                             sat_mult(A_im[rot_j][q], U_qq_im);
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 5;
                        end
                    end else if (rot_step == 5) begin
                        // Copy temp back to column p
                        if (rot_j < N) begin
                            A_re[rot_j][p] <= temp_re[rot_j];
                            A_im[rot_j][p] <= temp_im[rot_j];
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 6;
                        end
                    end else if (rot_step == 6) begin
                        // Zero out off-diagonal
                        A_re[p][q] <= 0;
                        A_im[p][q] <= 0;
                        A_re[q][p] <= 0;
                        A_im[q][p] <= 0;

                        // Update eigenvectors V = V * U
                        rot_step <= 7;
                    end else if (rot_step == 7) begin
                        // Update column p of V
                        if (rot_j < N) begin
                            temp_re[rot_j] <= sat_mult(V_re[rot_j][p], U_pp_re) - 
                                             sat_mult(V_im[rot_j][p], U_pp_im) +
                                             sat_mult(V_re[rot_j][q], U_qp_re) - 
                                             sat_mult(V_im[rot_j][q], U_qp_im);
                            temp_im[rot_j] <= sat_mult(V_re[rot_j][p], U_pp_im) + 
                                             sat_mult(V_im[rot_j][p], U_pp_re) +
                                             sat_mult(V_re[rot_j][q], U_qp_im) + 
                                             sat_mult(V_im[rot_j][q], U_qp_re);
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 8;
                        end
                    end else if (rot_step == 8) begin
                        // Update column q of V
                        if (rot_j < N) begin
                            V_re[rot_j][q] <= sat_mult(V_re[rot_j][p], U_pq_re) - 
                                             sat_mult(V_im[rot_j][p], U_pq_im) +
                                             sat_mult(V_re[rot_j][q], U_qq_re) - 
                                             sat_mult(V_im[rot_j][q], U_qq_im);
                            V_im[rot_j][q] <= sat_mult(V_re[rot_j][p], U_pq_im) + 
                                             sat_mult(V_im[rot_j][p], U_pq_re) +
                                             sat_mult(V_re[rot_j][q], U_qq_im) + 
                                             sat_mult(V_im[rot_j][q], U_qq_re);
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 9;
                        end
                    end else if (rot_step == 9) begin
                        // Copy temp back to column p of V
                        if (rot_j < N) begin
                            V_re[rot_j][p] <= temp_re[rot_j];
                            V_im[rot_j][p] <= temp_im[rot_j];
                            rot_j <= rot_j + 1;
                        end else begin
                            rot_j <= 0;
                            rot_step <= 10;
                        end
                    end else begin
                        // Rotation complete
                        rot_step <= 0;
                    end
                end

                CHECK_CONV: begin
                    iter <= iter + 1;
                    iter_count <= iter + 1;

                    // Check convergence or max iterations
                    if (off_diag_max < CONV_THRESHOLD || iter >= MAX_ITERATIONS - 1) begin
                        // Converged or max iterations reached
                        // Output results
                        for (ii = 0; ii < N; ii = ii + 1) begin
                            for (jj = 0; jj < N; jj = jj + 1) begin
                                a_re_out[(ii*N+jj+1)*W-1 -: W] <= A_re[ii][jj];
                                a_im_out[(ii*N+jj+1)*W-1 -: W] <= A_im[ii][jj];
                                v_re_out[(ii*N+jj+1)*W-1 -: W] <= V_re[ii][jj];
                                v_im_out[(ii*N+jj+1)*W-1 -: W] <= V_im[ii][jj];
                            end
                        end
                        done <= 1;
                        busy <= 0;
                    end else begin
                        // Continue iterating
                        i <= 0;
                        j <= 1;
                        off_diag_max <= 0;
                        p <= 0;
                        q <= 1;
                    end
                end

                DONE_STATE: begin
                    done <= 1;
                    busy <= 0;
                end
            endcase
        end
    end

    // Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = FIND_MAX;
            end

            FIND_MAX: begin
                if (i == N-2 && j == N-1)
                    next_state = COMPUTE_ANGLES;
            end

            COMPUTE_ANGLES: begin
                next_state = ROTATE;
            end

            ROTATE: begin
                if (rot_step == 10)
                    next_state = CHECK_CONV;
            end

            CHECK_CONV: begin
                if (off_diag_max < CONV_THRESHOLD || iter >= MAX_ITERATIONS - 1)
                    next_state = DONE_STATE;
                else
                    next_state = FIND_MAX;
            end

            DONE_STATE: begin
                if (!start)
                    next_state = IDLE;
            end

            default: next_state = IDLE;
        endcase
    end

endmodule

// Top-level wrapper for eigenvalue decomposition
// Standard handshake interface with cycle counting

module top #(
    parameter N = 10,
    parameter W = 46
)(
