    output wire [N*N*W-1:0] a_im_out,
    output wire [N*N*W-1:0] v_re_out,
    output wire [N*N*W-1:0] v_im_out,

    output wire [15:0] iter_count,
    output wire busy,
    output wire done,
    output reg  [31:0] cycles
);

    // Instantiate eigenvalue decomposition module
    eigenvalue_decomposition #(
        .MATRIX_SIZE(N),
        .MAX_ITERATIONS(2000),
        .W(W),
        .Q(14)
    ) eig_inst (
        .clk(clk),
