        .v_im_out(v_im_out),
        .iter_count(iter_count),
        .busy(busy),
        .done(done)
    );

    // Cycle counter
    reg start_reg;
    reg counting;

    always @(posedge clk) begin
        if (rst) begin
            cycles <= 0;
            start_reg <= 0;
            counting <= 0;
        end else begin
            start_reg <= start;

            // Detect rising edge of start
            if (start && !start_reg) begin
                cycles <= 0;
                counting <= 1;
            end

            // Count cycles while busy
            if (counting) begin
                cycles <= cycles + 1;
            end

            // Stop counting when done
            if (done) begin
                counting <= 0;
            end
        end
    end

