// Testbench for eigenvalue decomposition
// Reads reference inputs, runs decomposition, writes diagonal outputs

`timescale 1ns/1ps

module tb_top;

    parameter N = 10;
    parameter W = 46;
    parameter CLK_PERIOD = 10; // 100 MHz

    reg clk;
    reg rst;
    reg start;

    reg  [N*N*W-1:0] a_re_in;
    reg  [N*N*W-1:0] a_im_in;
    wire [N*N*W-1:0] a_re_out;
    wire [N*N*W-1:0] a_im_out;
    wire [N*N*W-1:0] v_re_out;
    wire [N*N*W-1:0] v_im_out;
    wire [15:0] iter_count;
    wire busy;
    wire done;
    wire [31:0] cycles;

    // DUT instantiation
    top #(
        .N(N),
        .W(W)
    ) dut (
        .clk(clk),
        .rst(rst),
        .start(start),
        .a_re_in(a_re_in),
        .a_im_in(a_im_in),
        .a_re_out(a_re_out),
        .a_im_out(a_im_out),
        .v_re_out(v_re_out),
        .v_im_out(v_im_out),
        .iter_count(iter_count),
        .busy(busy),
        .done(done),
        .cycles(cycles)
    );

    // Clock generation
    initial begin
        clk = 0;
        forever #(CLK_PERIOD/2) clk = ~clk;
    end

    // Input matrix storage
    reg signed [W-1:0] matrix_re [0:N*N-1];
    reg signed [W-1:0] matrix_im [0:N*N-1];

    // Output matrix storage
    reg signed [W-1:0] out_re [0:N*N-1];
    reg signed [W-1:0] out_im [0:N*N-1];

    integer i, j;
    integer in_file, out_file, meta_file;
    integer scan_ret;
    reg signed [W-1:0] temp_re, temp_im;

    initial begin
        // Initialize signals
        rst = 1;
        start = 0;
        a_re_in = 0;
        a_im_in = 0;

        // Wait for reset
        repeat(10) @(posedge clk);
        rst = 0;
        repeat(5) @(posedge clk);

        // Read input matrix from file
        in_file = $fopen("../reference_inputs.txt", "r");
        if (in_file == 0) begin
            $display("ERROR: Could not open reference_inputs.txt");
            $finish;
        end

        $display("Reading input matrix...");
        for (i = 0; i < N*N; i = i + 1) begin
            scan_ret = $fscanf(in_file, "%d %d\n", temp_re, temp_im);
            if (scan_ret != 2) begin
                $display("ERROR: Failed to read element %d", i);
                $finish;
            end
            matrix_re[i] = temp_re;
            matrix_im[i] = temp_im;
        end
        $fclose(in_file);

        // Pack matrix into input vector (row-major order)
        for (i = 0; i < N*N; i = i + 1) begin
            a_re_in[(i+1)*W-1 -: W] = matrix_re[i];
            a_im_in[(i+1)*W-1 -: W] = matrix_im[i];
        end

        $display("Starting eigenvalue decomposition...");

        // Assert start
        @(posedge clk);
        start = 1;
        @(posedge clk);
        start = 0;

        // Wait for completion with timeout
        fork
            begin
                @(posedge done);
                $display("Decomposition complete!");
                $display("Iterations: %d", iter_count);
                $display("Cycles: %d", cycles);
            end
            begin
                repeat(100000) @(posedge clk);
                $display("ERROR: Timeout waiting for done signal");
                $finish;
            end
        join_any
        disable fork;

        // Wait a few cycles
        repeat(5) @(posedge clk);

        // Extract output matrix
        for (i = 0; i < N*N; i = i + 1) begin
            out_re[i] = a_re_out[(i+1)*W-1 -: W];
            out_im[i] = a_im_out[(i+1)*W-1 -: W];
        end

        // Write diagonal elements to output file
        out_file = $fopen("sim/sim_diag_out.txt", "w");
        if (out_file == 0) begin
            $display("ERROR: Could not open sim_diag_out.txt for writing");
            $finish;
        end

        $display("Writing diagonal elements...");
        for (i = 0; i < N; i = i + 1) begin
            $fwrite(out_file, "%d %d\n", out_re[i*N+i], out_im[i*N+i]);
        end
        $fclose(out_file);

        // Write metadata
        meta_file = $fopen("sim/sim_meta.txt", "w");
        if (meta_file == 0) begin
            $display("ERROR: Could not open sim_meta.txt for writing");
            $finish;
        end

        $fwrite(meta_file, "iter_count %d\n", iter_count);
        $fwrite(meta_file, "cycles %d\n", cycles);
        $fclose(meta_file);

        $display("Test complete. Results written to sim/sim_diag_out.txt");
        $finish;
    end

    // Timeout watchdog
    initial begin
        #10000000; // 10ms timeout
        $display("ERROR: Simulation timeout");
        $finish;
    end

endmodule

