        .start(start),
        .a_re_in(a_re_in),
        .a_im_in(a_im_in),
        .a_re_out(a_re_out),
        .a_im_out(a_im_out),
        .v_re_out(v_re_out),
        .v_im_out(v_im_out),
        .iter_count(iter_count),
        .busy(busy),
        .done(done),
        .cycles(cycles)
    );

    // Clock generation
    initial begin
        clk = 0;
        forever #(CLK_PERIOD/2) clk = ~clk;
    end

