            state <= IDLE;
            valid_out <= 0;
            iter_count <= 0;
            iterations <= 0;
            max_off_diag <= 0;
            max_p <= 0;
            max_q <= 1;
            p <= 0;
            q <= 1;
            search_i <= 0;
            search_j <= 0;
            update_row <= 0;
            update_col <= 0;

            for (i = 0; i < N*N; i = i + 1) begin
                A_re[i] <= 0;
                A_im[i] <= 0;
